// mm/src/pages/workflowPage.js
import React, { useMemo } from 'react';
import { Routes, Route, Navigate, useNavigate } from 'react-router-dom';

import WorkflowContainer from '../components/WorkflowContainer';
import UploadStep from '../steps/uploadStep';
import DesignStep from '../steps/designStep';
import PreviewStep from '../steps/previewStage';
import DetailsStep from '../steps/detailsStep';
import DownloadStep from '../steps/downloadStep';
import { useWorkflow } from '../store/workflowContext';

const WorkflowPage = () => {
  const nav = useNavigate();

  const {
    manuscriptFiles,
    uploadPhase,
    setUploadPhase,
    bookDetails,
    design,
    setDesign,
  } = useWorkflow();

  // ---- STEP 1: Upload gating ----
  const hasFiles = !!(manuscriptFiles && manuscriptFiles.length > 0);

  // Which Upload screen is currently shown?
  const isSelect = uploadPhase === 'select';
  const isReady = uploadPhase === 'ready';
  const isMeta = uploadPhase === 'metadata';

  // In metadata screen, require title + category + subcategory (you can relax this later)
  const metaComplete = useMemo(() => {
    if (!isMeta) return false;
    const t = (bookDetails?.title || '').trim();
    const c = (bookDetails?.category || '').trim();
    const s = (bookDetails?.subcategory || '').trim();
    return t.length > 0 && c.length > 0 && s.length > 0;
  }, [isMeta, bookDetails]);

  // Control the main Continue button on the Upload route:
  // - select: allow Continue only if file exists (but your UI may not use it; harmless)
  // - ready: HIDE Continue (you want Start AI Analysis instead)
  // - metadata: show Continue when metadata complete
  const hideNextUpload = isReady; // <- your request: no Continue on the Start AI Analysis screen
  const canProceedUpload = isMeta ? metaComplete : hasFiles;

  const handleUploadNext = () => {
    // Phase transitions inside Upload route
    if (isSelect) {
      // If a file exists already, move to ready; otherwise do nothing.
      if (hasFiles) setUploadPhase('ready');
      return;
    }

    if (isReady) {
      // This path is usually not used because Continue is hidden,
      // but leaving it here keeps logic consistent.
      setUploadPhase('metadata');
      return;
    }

    if (isMeta) {
      // Metadata completed -> go to Design
      // Reset/initialize design stage when entering Design
      setDesign({
        ...(design || {}),
        analyzed: true,
        stage: 'typography',
      });
      nav('/workflow/design');
    }
  };

  const handleUploadPrevious = () => {
    if (isMeta) return setUploadPhase('ready');
    if (isReady) return setUploadPhase('select');
    // select -> home
    nav('/');
  };

  // ---- STEP 2: Design mini-wizard ----
  const handleDesignNext = () => {
    if (!design) return;

    if (design.stage === 'typography') {
      setDesign({ ...design, stage: 'layout' });
      return;
    }

    if (design.stage === 'layout') {
      setDesign({ ...design, stage: 'trim' });
      return;
    }

    if (design.stage === 'trim') {
      setDesign({ ...design, stage: 'summary' });
      return;
    }

    if (design.stage === 'summary') {
      nav('/workflow/preview');
    }
  };

  const handleDesignPrevious = () => {
    if (!design) {
      nav('/workflow/start');
      return;
    }

    if (design.stage === 'summary') {
      setDesign({ ...design, stage: 'trim' });
      return;
    }

    if (design.stage === 'trim') {
      setDesign({ ...design, stage: 'layout' });
      return;
    }

    if (design.stage === 'layout') {
      setDesign({ ...design, stage: 'typography' });
      return;
    }

    if (design.stage === 'typography') {
      nav('/workflow/start');
    }
  };

  // You can tighten this later (e.g., require chosen typography/layout/trim)
  const canProceedDesign = true;

  return (
    <Routes>
      {/* Upload & Organize */}
      <Route
        path="start"
        element={
          <WorkflowContainer
            title="Upload & Organize"
            description="Upload your manuscript files and organize them for formatting"
            step={1}
            hideNext={hideNextUpload}
            canProceed={canProceedUpload}
            onNext={handleUploadNext}
            disableSavePrompt={true}
            onPrevious={handleUploadPrevious}
          >
            <UploadStep />
          </WorkflowContainer>
        }
      />

      {/* Design */}
      <Route
        path="design"
        element={
          <WorkflowContainer
            title="Design Your Book"
            description="Customize typography, layout, and format with AI-powered recommendations"
            step={2}
            canProceed={canProceedDesign}
            onNext={handleDesignNext}
            onPrevious={handleDesignPrevious}
          >
            <DesignStep />
          </WorkflowContainer>
        }
      />

      {/* Preview */}
      <Route
        path="preview"
        element={
          <WorkflowContainer
            title="Preview"
            description="Check how pages will look with your chosen design"
            step={3}
            canProceed={true}
            onPrevious={() => nav('/workflow/design')}
            onNext={() => nav('/workflow/details')}
          >
            <PreviewStep />
          </WorkflowContainer>
        }
      />

      {/* Details */}
      <Route
        path="details"
        element={
          <WorkflowContainer
            title="Details"
            description="Add book metadata and publishing options"
            step={4}
            canProceed={true}
            onPrevious={() => nav('/workflow/preview')}
            onNext={() => nav('/workflow/download')}
          >
            <DetailsStep />
          </WorkflowContainer>
        }
      />

      {/* Download */}
      <Route
        path="download"
        element={
          <WorkflowContainer
            title="Download"
            description="Download formatted files and upload packages"
            step={5}
            canProceed={true}
            onPrevious={() => nav('/workflow/details')}
          >
            <DownloadStep />
          </WorkflowContainer>
        }
      />

      {/* Default /workflow → /workflow/start */}
      <Route index element={<Navigate to="start" replace />} />
    </Routes>
  );
};

export default WorkflowPage;
